interface Shape { String name(); }
class Circle implements Shape { public String name() { return "circle"; } }
class Square implements Shape { public String name() { return "square"; } }

class ShapeFactory {
    public static Shape create(String type) {
        if (type == "circle") return new Circle();
        if (type == "square") return new Square();
        throw new IllegalArgumentException("unknown: " + type);
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println(ShapeFactory.create("square").name());
    }
}
